import React, { useState } from 'react';
import '../styles/MovieForm.css';

const MovieForm = ({ initialData = {}, onSubmit, buttonText }) => {
  const [formData, setFormData] = useState({
    title: initialData.title || '',
    director: initialData.director || '',
    year: initialData.year || '',
    genre: initialData.genre || '',
    rating: initialData.rating || '',
    status: initialData.status || '',
    review: initialData.review || '',
    posterUrl: initialData.posterUrl || ''
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    onSubmit(formData);
  };

  const genres = ['Action', 'Comedy', 'Drama', 'Horror', 'Sci-Fi', 'Romance', 'Thriller', 'Documentary', 'Animation', 'Other'];
  const statuses = ['plan to watch', 'watching', 'watched'];

  return (
    <form className="movie-auth-form" onSubmit={handleSubmit}>
      <h1>{buttonText === 'Add Movie' ? 'Add New Movie' : 'Edit Movie'}</h1>
      
      <div className="input-box">
        <input
          type="text"
          name="title"
          placeholder="Movie Title *"
          value={formData.title}
          onChange={handleChange}
          required
        />
        <i className='bx bx-camera-movie'></i>
      </div>

      <div className="input-row">
        <div className="input-box">
          <input
            type="text"
            name="director"
            placeholder="Director"
            value={formData.director}
            onChange={handleChange}
          />
          <i className='bx bx-user'></i>
        </div>

        <div className="input-box">
          <input
            type="number"
            name="year"
            placeholder="Year"
            min="1888"
            max={new Date().getFullYear() + 5}
            value={formData.year}
            onChange={handleChange}
          />
          <i className='bx bx-calendar'></i>
        </div>
      </div>

      <div className="input-row">
        <div className="input-box select-box">
          <select name="genre" value={formData.genre} onChange={handleChange} required>
            <option value="" disabled>Select Genre *</option>
            {genres.map(genre => (
              <option key={genre} value={genre}>{genre}</option>
            ))}
          </select>
          <i className='bx bx-category'></i>
        </div>

        <div className="input-box select-box">
          <select name="status" value={formData.status} onChange={handleChange} required>
            <option value="" disabled>Select Status *</option>
            {statuses.map(status => (
              <option key={status} value={status}>{status}</option>
            ))}
          </select>
          <i className='bx bx-bookmark'></i>
        </div>
      </div>

      <div className="input-row">
        <div className="input-box">
          <input
            type="number"
            name="rating"
            placeholder="Rating (0-10)"
            min="0"
            max="10"
            step="0.1"
            value={formData.rating}
            onChange={handleChange}
          />
          <i className='bx bx-star'></i>
        </div>

        <div className="input-box">
          <input
            type="url"
            name="posterUrl"
            placeholder="Poster URL"
            value={formData.posterUrl}
            onChange={handleChange}
          />
          <i className='bx bx-image'></i>
        </div>
      </div>

      <div className="input-box">
        <textarea
          name="review"
          placeholder="Write your review here..."
          rows="2"
          value={formData.review}
          onChange={handleChange}
        />
        <i className='bx bx-edit-alt'></i>
      </div>

      <button type="submit" className="btn">
        {buttonText || 'Save Movie'}
      </button>
    </form>
  );
};

export default MovieForm;
